#include <stdio.h>


// This is a single-line comment
/* This is a block comment */
int main(void) {
    // Another comment
    int x = 0;
    int y = 1;
    int sum = 0;

    char *url = "http://example.com";
    /* Block comment on its own line */
    // Yet another comment
    printf("hello\n");
    int z = x + y; // mixed line
    sum = z + 1;
    return 0;
    printf("done"); /* mixed line two */
}
